#include <stdint.h>
#define STM_DRIVER_IMPLEMENTATION
#include "Nucleo_Driver.h"


int main(void)
{
    // Setup
	initialiseMCU();
    pinMode(PB4, ALTERNATE);
    analogWrite(PB4, 26);
    
    /* Loop forever */
    while(1)
    {
        for(int i = 0; i < 256; i++)
        {
            analogWrite(PB4, i);
            delay(100);
        }

        for(int j = 255; j > 1; j--)
        {
            analogWrite(PB4, j);
            delay(100);
        }
        
    }
}
